import React, { useState, useEffect } from 'react';
import { materialAPI } from '../services/api';

const MaterialsUploadPage = () => {
  const [materials, setMaterials] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [successMessage, setSuccessMessage] = useState('');
  const [showForm, setShowForm] = useState(false);
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    subject: '',
    topic: '',
    file: null,
  });

  useEffect(() => {
    fetchMaterials();
  }, []);

  const fetchMaterials = async () => {
    setLoading(true);
    setError('');
    try {
      const res = await materialAPI.getMyMaterials();
      setMaterials(res.data.materials || []);
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to fetch materials');
    } finally {
      setLoading(false);
    }
  };

  const handleInputChange = (e) => {
    const { name, value, files } = e.target;
    setFormData((prev) => ({ ...prev, [name]: name === 'file' ? files[0] : value }));
  };

  const handleUploadMaterial = async (e) => {
    e.preventDefault();
    setError('');

    if (!formData.title || !formData.subject || !formData.file) {
      setError('Please complete the required fields before uploading.');
      return;
    }

    try {
      const formDataToSend = new FormData();
      formDataToSend.append('title', formData.title);
      formDataToSend.append('description', formData.description);
      formDataToSend.append('subject', formData.subject);
      formDataToSend.append('topic', formData.topic);
      formDataToSend.append('file', formData.file);

      await materialAPI.uploadMaterial(formDataToSend);
      setSuccessMessage('Material uploaded successfully.');
      setTimeout(() => setSuccessMessage(''), 3000);
      setFormData({ title: '', description: '', subject: '', topic: '', file: null });
      setShowForm(false);
      fetchMaterials();
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to upload material');
    }
  };

  const handleDeleteMaterial = async (materialId) => {
    if (!window.confirm('Delete this material?')) return;

    try {
      await materialAPI.deleteMaterial(materialId);
      setSuccessMessage('Material deleted successfully.');
      setTimeout(() => setSuccessMessage(''), 3000);
      fetchMaterials();
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to delete material');
    }
  };

  return (
    <div className="container-fluid py-4 min-vh-100">
      <div className="container">
        <div className="portal-page-header">
          <span className="portal-page-kicker">Resources</span>
          <h1 className="portal-page-title">Manage Materials</h1>
          <p className="portal-page-subtitle">
            Upload, organize, and maintain the study resources students will use before and after
            sessions.
          </p>
        </div>

        {error && (
          <div className="alert alert-danger alert-dismissible fade show" role="alert">
            {error}
            <button type="button" className="btn-close" onClick={() => setError('')}></button>
          </div>
        )}

        {successMessage && (
          <div className="alert alert-success alert-dismissible fade show" role="alert">
            {successMessage}
            <button
              type="button"
              className="btn-close"
              onClick={() => setSuccessMessage('')}
            ></button>
          </div>
        )}

        <div className="row g-4 mb-4">
          <div className="col-md-4">
            <div className="card portal-stat-card shadow-sm">
              <div className="card-body">
                <div className="portal-stat-label">Materials</div>
                <div className="portal-stat-value">{materials.length}</div>
              </div>
            </div>
          </div>
          <div className="col-md-8">
            <div className="card portal-section-card shadow-sm">
              <div className="card-body d-flex justify-content-between align-items-center flex-wrap gap-3">
                <div>
                  <div className="portal-stat-label">Action</div>
                  <div className="fw-semibold">Upload and manage teaching resources</div>
                </div>
                <button className="btn btn-primary" onClick={() => setShowForm(!showForm)}>
                  {showForm ? 'Close Form' : 'Upload Material'}
                </button>
              </div>
            </div>
          </div>
        </div>

        {showForm && (
          <div className="card portal-section-card shadow-sm mb-4">
            <div className="card-header bg-primary fw-bold">Upload New Material</div>
            <div className="card-body p-4">
              <form onSubmit={handleUploadMaterial}>
                <div className="mb-3">
                  <label htmlFor="title" className="form-label">Title</label>
                  <input
                    type="text"
                    className="form-control"
                    id="title"
                    name="title"
                    value={formData.title}
                    onChange={handleInputChange}
                    required
                  />
                </div>
                <div className="mb-3">
                  <label htmlFor="description" className="form-label">Description</label>
                  <textarea
                    className="form-control"
                    id="description"
                    name="description"
                    value={formData.description}
                    onChange={handleInputChange}
                    rows="3"
                  ></textarea>
                </div>
                <div className="row">
                  <div className="col-md-6 mb-3">
                    <label htmlFor="subject" className="form-label">Subject</label>
                    <input
                      type="text"
                      className="form-control"
                      id="subject"
                      name="subject"
                      value={formData.subject}
                      onChange={handleInputChange}
                      required
                    />
                  </div>
                  <div className="col-md-6 mb-3">
                    <label htmlFor="topic" className="form-label">Topic</label>
                    <input
                      type="text"
                      className="form-control"
                      id="topic"
                      name="topic"
                      value={formData.topic}
                      onChange={handleInputChange}
                    />
                  </div>
                </div>
                <div className="mb-4">
                  <label htmlFor="file" className="form-label">File</label>
                  <input
                    type="file"
                    className="form-control"
                    id="file"
                    name="file"
                    onChange={handleInputChange}
                    accept=".pdf,.doc,.docx,.ppt,.pptx,.jpg,.jpeg,.png,.gif"
                    required
                  />
                  <small className="text-muted">
                    Supported formats: PDF, DOC, DOCX, PPT, PPTX, and image files.
                  </small>
                </div>
                <button type="submit" className="btn btn-primary w-100">Upload Material</button>
              </form>
            </div>
          </div>
        )}

        {loading ? (
          <div className="text-center py-5">
            <div className="spinner-border text-primary" role="status">
              <span className="visually-hidden">Loading...</span>
            </div>
          </div>
        ) : materials.length === 0 ? (
          <div className="card portal-section-card shadow-sm">
            <div className="portal-empty-state">No materials uploaded yet.</div>
          </div>
        ) : (
          <div className="row g-4">
            {materials.map((material) => (
              <div key={material._id} className="col-md-6 col-lg-4">
                <div className="card portal-resource-card shadow-sm">
                  <div className="card-body p-4">
                    <div className="portal-stat-label mb-2">{material.subject}</div>
                    <h5 className="fw-bold mb-2">{material.title}</h5>
                    <p className="text-muted mb-4">{material.description || 'No description provided.'}</p>
                    <div className="portal-meta-list">
                      <div className="portal-meta-item">
                        <strong>Topic:</strong> {material.topic || 'General'}
                      </div>
                      <div className="portal-meta-item">
                        <strong>Uploaded:</strong> {new Date(material.uploadedAt).toLocaleDateString()}
                      </div>
                    </div>
                  </div>
                  <div className="card-footer bg-transparent border-0 pt-0 px-4 pb-4 d-grid gap-2">
                    <a
                      href={`http://localhost:5000${material.fileUrl}`}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="btn btn-outline-primary"
                    >
                      View Material
                    </a>
                    <button className="btn btn-danger" onClick={() => handleDeleteMaterial(material._id)}>
                      Delete Material
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default MaterialsUploadPage;
